import { readStudioMapping } from "../chatSessions/arming.js";
export function runRecoverStudio() {
    const agentSessionId = process.argv[2];
    if (!agentSessionId) {
        process.stdout.write(`${JSON.stringify({ error: "missing-agent-session-id" })}\n`);
        process.exit(1);
    }
    const mapping = readStudioMapping(agentSessionId);
    if (mapping) {
        process.stdout.write(`${JSON.stringify({
            studioSessionId: mapping.studioSessionId,
            agentSessionId,
        })}\n`);
    }
    else {
        process.stdout.write(`${JSON.stringify({ error: "no-active-studio", agentSessionId })}\n`);
        process.exit(1);
    }
}
runRecoverStudio();
